#include <stdio.h>

int Search(int arr[], int x, int n) {
    for (int i = 0; i < n; ++i) {
        if (arr[i] == x) {
            return i + 1; // 1‑based index
        }
    }
    return -1;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, X;
        scanf("%d %d", &N, &X);
        int arr[1000]; // N <= 1000
        for (int i = 0; i < N; ++i) {
            scanf("%d", &arr[i]);
        }
        printf("%d\n", Search(arr, X, N));
    }
    return 0;
}

