import sys

def search(arr, x):
    for i, val in enumerate(arr):
        if val == x:
            return i + 1  # 1‑based
    return -1

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        X = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        out.append(str(search(arr, X)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

